export type ChatMessage = {
  id: string;
  role: "user" | "assistant";
  content: string;
};

type ChatMessageListProps = {
  messages?: ChatMessage[];
};

export default function ChatMessageList({ messages = [] }: ChatMessageListProps) {
  return (
    <div
      className="chat-messages"
      role="log"
      aria-live="polite"
      aria-label="Conversation"
