1	/* ---------------------------------------------------------------------------
2	 * useChat — suite 19/P03 + 19/P04
3	 * Client-side state machine for the chat conversation. Owns the message list,
4	 * issues SSE requests against /api/chat, progressively appends streamed
5	 * tokens to an assistant placeholder, and surfaces error / rate-limit state
6	 * so the UI can render a retry affordance.
7	 *
8	 * 19/P04: optional opt-in persistence to localStorage["llm.chat.history.v1"]
9	 * gated by the user-facing toggle pref at "llm.chat.persist.v1". The hook
10	 * coexists with the toggle housed in ChatHeader; both ends sync via storage
11	 * events (cross-tab) and a custom "llm-chat-persist-change" event (same tab).
12	 * --------------------------------------------------------------------------- */
13	
14	"use client";
15	
16	import { useCallback, useEffect, useRef, useState } from "react";
17	
18	import {
19	  type ChatMetaPayload,
20	  type Citation,
21	  type ClientChatMessage,
22	} from "@/lib/llm/chatTypes";
23	import { streamReader } from "@/lib/llm/streamReader";
24	
25	export type ChatStatus = "idle" | "streaming" | "error";
26	
27	export type UseChatReturn = {
28	  messages: ClientChatMessage[];
29	  status: ChatStatus;
30	  submit: (text: string) => Promise<void>;
31	  retry: () => Promise<void>;
32	  clear: () => void;
33	  stopStreaming: () => void;
34	  lastError?: string;
35	  persist: boolean;
36	  setPersist: (next: boolean) => void;
37	};
38	
39	const HISTORY_KEY = "llm.chat.history.v1";
40	const PERSIST_KEY = "llm.chat.persist.v1";
41	const PERSIST_EVENT = "llm-chat-persist-change";
42	const HISTORY_CAP = 100;
43	const SERVER_HISTORY_LIMIT = 40;
44	
45	let _idCounter = 0;
46	function nextId(prefix: string): string {
47	  _idCounter += 1;
48	  return `${prefix}-${Date.now().toString(36)}-${_idCounter}`;
49	}
50	
51	type ServerMessage = { role: "user" | "assistant"; content: string };
52	
53	function readPersistPref(): boolean {
54	  if (typeof window === "undefined") return false;
55	  try {
56	    return window.localStorage.getItem(PERSIST_KEY) === "1";
57	  } catch {
58	    return false;
59	  }
60	}
61	
62	function readHistory(): ClientChatMessage[] {
63	  if (typeof window === "undefined") return [];
64	  try {
65	    const raw = window.localStorage.getItem(HISTORY_KEY);
66	    if (!raw) return [];
67	    const parsed: unknown = JSON.parse(raw);
68	    if (!Array.isArray(parsed)) return [];
69	    const restored: ClientChatMessage[] = [];
70	    for (const entry of parsed) {
71	      if (!entry || typeof entry !== "object") continue;
72	      const m = entry as Record<string, unknown>;
73	      if (typeof m.id !== "string") continue;
74	      if (typeof m.content !== "string") continue;
75	      if (m.role !== "user" && m.role !== "assistant") continue;
76	      if (typeof m.createdAt !== "number") continue;
77	      const status =
78	        m.status === "error" || m.status === "streaming"
79	          ? "complete"
80	          : "complete";
81	      restored.push({
82	        id: m.id,
83	        role: m.role,
84	        content: m.content,
85	        status,
86	        createdAt: m.createdAt,
87	        citations: Array.isArray(m.citations)
88	          ? (m.citations as Citation[])
89	          : undefined,
90	      });
91	    }
92	    return restored.slice(-HISTORY_CAP);
93	  } catch {
94	    return [];
95	  }
96	}
97	
98	function writeHistory(messages: ClientChatMessage[]): void {
99	  if (typeof window === "undefined") return;
100	  try {
101	    const trimmed = messages
102	      .filter((m) => m.status !== "streaming")
103	      .slice(-HISTORY_CAP);
104	    window.localStorage.setItem(HISTORY_KEY, JSON.stringify(trimmed));
105	  } catch {
106	    // quota exceeded or storage unavailable — degrade silently.
107	  }
108	}
109	
110	function clearHistoryStorage(): void {
111	  if (typeof window === "undefined") return;
112	  try {
113	    window.localStorage.removeItem(HISTORY_KEY);
114	  } catch {
115	    // ignore
116	  }
117	}
118	
119	function writePersistPref(next: boolean): void {
120	  if (typeof window === "undefined") return;
121	  try {
122	    if (next) window.localStorage.setItem(PERSIST_KEY, "1");
123	    else window.localStorage.removeItem(PERSIST_KEY);
124	  } catch {
125	    // ignore
126	  }
127	  try {
128	    window.dispatchEvent(
129	      new CustomEvent(PERSIST_EVENT, { detail: { value: next } }),
130	    );
131	  } catch {
132	    // ignore
133	  }
134	}
135	
136	export function useChat(): UseChatReturn {
137	  const [messages, setMessages] = useState<ClientChatMessage[]>([]);
138	  const [status, setStatus] = useState<ChatStatus>("idle");
139	  const [lastError, setLastError] = useState<string | undefined>(undefined);
140	  const [persist, setPersistState] = useState<boolean>(false);
141	
142	  const abortRef = useRef<AbortController | null>(null);
143	  const lastUserTextRef = useRef<string | null>(null);
144	  const messagesRefSnapshot = useRef<ClientChatMessage[]>([]);
145	  messagesRefSnapshot.current = messages;
146	  const persistRef = useRef<boolean>(false);
147	  persistRef.current = persist;
148	  const hydratedRef = useRef<boolean>(false);
149	
150	  // Hydrate from localStorage on mount: read persistence pref and, if on,
151	  // restore prior messages. This runs once.
152	  useEffect(() => {
153	    const pref = readPersistPref();
154	    setPersistState(pref);
155	    if (pref) {
156	      const restored = readHistory();
157	      if (restored.length > 0) {
158	        setMessages(restored);
159	        const lastUser = [...restored]
160	          .reverse()
161	          .find((m) => m.role === "user");
162	        if (lastUser) lastUserTextRef.current = lastUser.content;
163	      }
164	    }
165	    hydratedRef.current = true;
166	  }, []);
167	
168	  // Persist message list to localStorage whenever it changes — but only if
169	  // the user has opted in. Skipped before hydration so we don't blow away
170	  // existing storage with the empty initial state.
171	  useEffect(() => {
172	    if (!hydratedRef.current) return;
173	    if (!persist) return;
174	    writeHistory(messages);
175	  }, [persist, messages]);
176	
177	  // Cross-tab + same-tab pref/history sync.
178	  useEffect(() => {
179	    if (typeof window === "undefined") return;
180	
181	    function onStorage(e: StorageEvent) {
182	      if (e.key === PERSIST_KEY) {
183	        const next = e.newValue === "1";
184	        setPersistState(next);
185	        if (next) {
186	          const restored = readHistory();
187	          if (restored.length > 0) setMessages(restored);
188	        }
189	      } else if (e.key === HISTORY_KEY) {
190	        if (!persistRef.current) return;
191	        if (e.newValue === null) {
192	          setMessages([]);
193	        } else {
194	          const restored = readHistory();
195	          setMessages(restored);
196	        }
197	      }
198	    }
199	
200	    function onLocalPref(e: Event) {
201	      const ce = e as CustomEvent<{ value: boolean }>;
202	      const next = Boolean(ce.detail?.value);
203	      setPersistState(next);
204	      if (next) {
205	        // Pref just turned on — flush current messages so a reload restores.
206	        writeHistory(messagesRefSnapshot.current);
207	      } else {
208	        clearHistoryStorage();
209	      }
210	    }
211	
212	    window.addEventListener("storage", onStorage);
213	    window.addEventListener(PERSIST_EVENT, onLocalPref as EventListener);
214	    return () => {
215	      window.removeEventListener("storage", onStorage);
216	      window.removeEventListener(PERSIST_EVENT, onLocalPref as EventListener);
217	    };
218	  }, []);
219	
220	  const setPersist = useCallback((next: boolean) => {
221	    setPersistState(next);
222	    writePersistPref(next);
223	    if (next) {
224	      writeHistory(messagesRefSnapshot.current);
225	    } else {
226	      clearHistoryStorage();
227	    }
228	  }, []);
229	
230	  const updateMessage = useCallback(
231	    (id: string, patch: Partial<ClientChatMessage>) => {
232	      setMessages((prev) =>
233	        prev.map((m) => (m.id === id ? { ...m, ...patch } : m)),
234	      );
235	    },
236	    [],
237	  );
238	
239	  const appendToken = useCallback((id: string, token: string) => {
240	    setMessages((prev) =>
241	      prev.map((m) =>
242	        m.id === id ? { ...m, content: m.content + token } : m,
243	      ),
244	    );
245	  }, []);
246	
247	  const runStream = useCallback(
248	    async (historyForServer: ServerMessage[], placeholderId: string) => {
249	      setStatus("streaming");
250	      setLastError(undefined);
251	
252	      const controller = new AbortController();
253	      abortRef.current = controller;
254	
255	      let response: Response;
256	      try {
257	        response = await fetch("/api/chat", {
258	          method: "POST",
259	          headers: { "Content-Type": "application/json" },
260	          body: JSON.stringify({ messages: historyForServer }),
261	          signal: controller.signal,
262	        });
263	      } catch (err) {
264	        abortRef.current = null;
265	        if (controller.signal.aborted) {
266	          updateMessage(placeholderId, { status: "complete" });
267	          setStatus("idle");
268	          return;
269	        }
270	        const detail = err instanceof Error ? err.message : "network error";
271	        updateMessage(placeholderId, { status: "error" });
272	        setLastError(detail);
273	        setStatus("error");
274	        return;
275	      }
276	
277	      if (!response.ok) {
278	        let detail = `request failed (${response.status})`;
279	        try {
280	          const body = (await response.json()) as {
281	            error?: string;
282	            detail?: string;
283	          };
284	          if (typeof body.detail === "string" && body.detail) {
285	            detail = body.detail;
286	          } else if (typeof body.error === "string" && body.error) {
287	            detail = body.error;
288	          }
289	        } catch {
290	          // body was not JSON; use the default detail.
291	        }
292	        if (response.status === 429) {
293	          detail = `Rate limited — ${detail}. Please wait a moment and retry.`;
294	        }
295	        abortRef.current = null;
296	        updateMessage(placeholderId, { status: "error" });
297	        setLastError(detail);
298	        setStatus("error");
299	        return;
300	      }
301	
302	      try {
303	        for await (const frame of streamReader(response)) {
304	          if (frame.event === "token") {
305	            let token: string;
306	            try {
307	              token = JSON.parse(frame.data) as string;
308	            } catch {
309	              token = frame.data;
310	            }
311	            if (typeof token === "string" && token.length > 0) {
312	              appendToken(placeholderId, token);
313	            }
314	          } else if (frame.event === "meta") {
315	            try {
316	              const meta = JSON.parse(frame.data) as ChatMetaPayload;
317	              const citations: Citation[] = (meta.citations ?? []).map(
318	                (c) => ({
319	                  id: c.id,
320	                  chunkId: c.chunkId,
321	                  snippet: c.snippet,
322	                }),
323	              );
324	              updateMessage(placeholderId, { citations });
325	            } catch {
326	              // malformed meta — ignore.
327	            }
328	          } else if (frame.event === "error") {
329	            let detail = "stream error";
330	            try {
331	              const body = JSON.parse(frame.data) as { detail?: string };
332	              if (typeof body?.detail === "string" && body.detail) {
333	                detail = body.detail;
334	              }
335	            } catch {
336	              // ignore
337	            }
338	            abortRef.current = null;
339	            updateMessage(placeholderId, { status: "error" });
340	            setLastError(detail);
341	            setStatus("error");
342	            return;
343	          } else if (frame.event === "done") {
344	            break;
345	          }
346	        }
347	
348	        updateMessage(placeholderId, { status: "complete" });
349	        setStatus("idle");
350	      } catch (err) {
351	        if (controller.signal.aborted) {
352	          updateMessage(placeholderId, { status: "complete" });
353	          setStatus("idle");
354	          return;
355	        }
356	        const detail = err instanceof Error ? err.message : "stream failed";
357	        updateMessage(placeholderId, { status: "error" });
358	        setLastError(detail);
359	        setStatus("error");
360	      } finally {
361	        abortRef.current = null;
362	      }
363	    },
364	    [appendToken, updateMessage],
365	  );
366	
367	  const submit = useCallback(
368	    async (text: string) => {
369	      const trimmed = text.trim();
370	      if (!trimmed) return;
371	      if (abortRef.current) return; // already streaming
372	
373	      const now = Date.now();
374	      const userMsg: ClientChatMessage = {
375	        id: nextId("u"),
376	        role: "user",
377	        content: trimmed,
378	        status: "complete",
379	        createdAt: now,
380	      };
381	      const placeholder: ClientChatMessage = {
382	        id: nextId("a"),
383	        role: "assistant",
384	        content: "",
385	        status: "streaming",
386	        createdAt: now + 1,
387	      };
388	
389	      lastUserTextRef.current = trimmed;
390	
391	      // Capture the latest message list synchronously so the request payload
392	      // includes the just-pushed user message — useState updates don't flush
393	      // before the request is built. Cap to last SERVER_HISTORY_LIMIT entries
394	      // so we never exceed the server-side validation ceiling even if the
