"use client";

import { useEffect, useState } from "react";
import Container from "@/components/primitives/Container";
import ChatHeader from "./ChatHeader";
import ChatMessageList, { type ChatMessage } from "./ChatMessageList";
import ChatInput from "./ChatInput";

export default function ChatSurface() {
  const [messages] = useState<ChatMessage[]>([]);
  const [draft, setDraft] = useState("");
  const [isStreaming] = useState(false);

  // Mark this page so the global SiteFooter can hide itself.
  useEffect(() => {
    const prev = document.body.dataset.page;
    document.body.dataset.page = "chat";
    return () => {
      if (prev === undefined) delete document.body.dataset.page;
      else document.body.dataset.page = prev;
    };
  }, []);

  function handleSubmit() {
    // Wired up in 19/P02 (streaming + corpus retrieval).
    // For now: clear the draft so the surface is interactive.
    setDraft("");
  }

  return (
    <Container size="narrow" as="section" className="chat-surface">
      <ChatHeader />
      <ChatMessageList messages={messages} />
      <ChatInput
        value={draft}
        onChange={setDraft}
        onSubmit={handleSubmit}
        isStreaming={isStreaming}
      />
    </Container>
  );
}

