          </Button>
        ) : (
          <Button
            type="submit"
            variant="solid"
            tone="accent"
            disabled={!canSubmit}
          >
            ask
          </Button>
        )}
        <span
          className={
            "chat-input__count" +
            (overLimit ? " chat-input__count--over" : "")
          }
          aria-live="polite"
        >
          {charCount} / {MAX_LEN}
        </span>
      </Cluster>
    </form>
  );
}

